  1→import { pointInPolygon, signedPolygonArea } from './polygon';
  2→import { nearestPointOnSegment, segmentIntersection } from './line';
  3→import { columnOutline } from './columnGeometry';
  4→import { ENDPOINT_MERGE_TOLERANCE, MIN_ROOM_AREA } from '@/domain/defaults';
  5→
  6→function projectParameter(point, start, end) {
  7→  const dx = end.x - start.x;
  8→  const dy = end.y - start.y;
  9→  const lenSq = dx * dx + dy * dy;
 10→  if (lenSq === 0) return 0;
 11→  return ((point.x - start.x) * dx + (point.y - start.y) * dy) / lenSq;
 12→}
 13→
 14→function pointsEqual(a, b, tolerance) {
 15→  const dx = a.x - b.x;
 16→  const dy = a.y - b.y;
 17→  return dx * dx + dy * dy <= tolerance * tolerance;
 18→}
 19→
 20→function pointOnSegment(point, start, end, tolerance) {
 21→  const t = projectParameter(point, start, end);
 22→  if (t < -1e-6 || t > 1 + 1e-6) return null;
 23→  const { point: projected } = nearestPointOnSegment(point, start, end);
 24→  const dx = projected.x - point.x;
 25→  const dy = projected.y - point.y;
 26→  if (dx * dx + dy * dy > tolerance * tolerance) return null;
 27→  return Math.max(0, Math.min(1, t));
 28→}
 29→
 30→function findOrAddVertex(vertices, point, tolerance) {
 31→  for (let i = 0; i < vertices.length; i++) {
 32→    if (pointsEqual(vertices[i], point, tolerance)) {
 33→      return i;
 34→    }
 35→  }
 36→  vertices.push({ x: point.x, y: point.y });
 37→  return vertices.length - 1;
 38→}
 39→
 40→function addUniqueEdge(edgeSet, edges, from, to) {
 41→  if (from === to) return;
 42→  const key = from < to ? `${from}-${to}` : `${to}-${from}`;
 43→  if (edgeSet.has(key)) return;
 44→  edgeSet.add(key);
 45→  edges.push({ from, to });
 46→}
 47→
 48→function addUniqueEdgePoint(edgePoints, edgeIndex, vi, t) {
 49→  const points = edgePoints[edgeIndex];
 50→  const existing = points.find(point => point.vi === vi);
 51→  if (existing) {
 52→    existing.t = Math.min(existing.t, Math.max(0, Math.min(1, t)));
 53→    return;
 54→  }
 55→  points.push({ vi, t: Math.max(0, Math.min(1, t)) });
 56→}
 57→
 58→function pointOnPolygonBoundary(point, polygon, tolerance) {
 59→  for (let i = 0; i < polygon.length; i++) {
 60→    const start = polygon[i];
 61→    const end = polygon[(i + 1) % polygon.length];
 62→    if (pointOnSegment(point, start, end, tolerance) !== null) {
 63→      return true;
 64→    }
 65→  }
 66→  return false;
 67→}
 68→
 69→function pointInsideOrOnColumn(point, column, tolerance) {
 70→  const outline = columnOutline(column);
 71→  return pointInPolygon(point, outline) || pointOnPolygonBoundary(point, outline, tolerance);
 72→}
 73→
 74→function normalizeWallsForColumns(walls, columns, tolerance) {
 75→  if (!columns.length) return walls;
 76→
 77→  return walls.map(wall => {
 78→    let start = { ...wall.start };
 79→    let end = { ...wall.end };
 80→
 81→    const startColumn = columns.find(column => pointInsideOrOnColumn(start, column, tolerance));
 82→    if (startColumn) {
 83→      start = { x: startColumn.x, y: startColumn.y };
 84→    }
 85→
 86→    const endColumn = columns.find(column => pointInsideOrOnColumn(end, column, tolerance));
 87→    if (endColumn) {
 88→      end = { x: endColumn.x, y: endColumn.y };
 89→    }
 90→
 91→    return {
 92→      ...wall,
 93→      start,
 94→      end,
 95→    };
 96→  });
 97→}
 98→
 99→function roomPolygonKey(points, precision = ENDPOINT_MERGE_TOLERANCE) {
100→  if (!points?.length) return '';
101→
102→  const labels = points.map(point => {
103→    const x = Math.round(point.x / precision);
104→    const y = Math.round(point.y / precision);
105→    return `${x}:${y}`;
106→  });
107→
108→  const variants = [];
109→  for (let i = 0; i < labels.length; i++) {
110→    variants.push(labels.slice(i).concat(labels.slice(0, i)).join('|'));
111→  }
112→
113→  const reversed = [...labels].reverse();
114→  for (let i = 0; i < reversed.length; i++) {
115→    variants.push(reversed.slice(i).concat(reversed.slice(0, i)).join('|'));
116→  }
117→
118→  variants.sort();
119→  return variants[0];
120→}
121→
122→function buildRawSegments(walls, vertices, tolerance) {
123→  const segments = [];
124→
125→  for (const wall of walls) {
126→    const from = findOrAddVertex(vertices, wall.start, tolerance);
127→    const to = findOrAddVertex(vertices, wall.end, tolerance);
128→    if (from === to) continue;
129→    segments.push({ from, to });
130→  }
131→
132→  for (let i = 0; i < segments.length; i++) {
133→    const segA = segments[i];
134→    const a1 = vertices[segA.from];
135→    const a2 = vertices[segA.to];
136→
137→    for (let j = i + 1; j < segments.length; j++) {
138→      const segB = segments[j];
139→      const b1 = vertices[segB.from];
140→      const b2 = vertices[segB.to];
141→      const intersection = segmentIntersection(a1, a2, b1, b2);
142→      if (!intersection) continue;
143→      findOrAddVertex(vertices, intersection, tolerance);
144→    }
145→  }
146→
147→  return segments;
148→}
149→
150→function buildColumnSegments(columns, vertices, tolerance) {
151→  const segments = [];
152→
153→  for (const column of columns) {
154→    const corners = columnOutline(column);
155→    const edgePoints = new Array(corners.length).fill(null).map(() => []);
156→
157→    for (let vi = 0; vi < vertices.length; vi++) {
158→      const vertex = vertices[vi];
159→      for (let edgeIndex = 0; edgeIndex < corners.length; edgeIndex++) {
160→        const c1 = corners[edgeIndex];
161→        const c2 = corners[(edgeIndex + 1) % corners.length];
162→        const t = pointOnSegment(vertex, c1, c2, tolerance);
163→        if (t === null) continue;
164→        addUniqueEdgePoint(edgePoints, edgeIndex, vi, t);
165→      }
166→    }
167→
168→    for (let cornerIndex = 0; cornerIndex < corners.length; cornerIndex++) {
169→      const prevEdge = (cornerIndex - 1 + corners.length) % corners.length;
170→      const nextEdge = cornerIndex;
171→      if (edgePoints[prevEdge].length === 0 || edgePoints[nextEdge].length === 0) continue;
172→
173→      const cornerVi = findOrAddVertex(vertices, corners[cornerIndex], tolerance);
174→      addUniqueEdgePoint(edgePoints, prevEdge, cornerVi, 1);
175→      addUniqueEdgePoint(edgePoints, nextEdge, cornerVi, 0);
176→    }
177→
178→    for (let edgeIndex = 0; edgeIndex < edgePoints.length; edgeIndex++) {
179→      const points = edgePoints[edgeIndex];
180→      if (points.length < 2) continue;
181→
182→      points.sort((a, b) => a.t - b.t);
183→      const orderedVertices = [];
184→      for (const point of points) {
185→        if (orderedVertices[orderedVertices.length - 1] !== point.vi) {
186→          orderedVertices.push(point.vi);
187→        }
188→      }
189→
190→      for (let i = 0; i < orderedVertices.length - 1; i++) {
191→        const from = orderedVertices[i];
192→        const to = orderedVertices[i + 1];
193→        if (from !== to) {
194→          segments.push({ from, to });
195→        }
196→      }
197→    }
198→  }
199→
200→  return segments;
201→}
202→
203→function subdivideSegments(rawSegments, vertices, tolerance) {
204→  const edges = [];
205→  const edgeSet = new Set();
206→
207→  for (const segment of rawSegments) {
208→    const start = vertices[segment.from];
209→    const end = vertices[segment.to];
210→    const splitPoints = [];
211→
212→    for (let vi = 0; vi < vertices.length; vi++) {
213→      const t = pointOnSegment(vertices[vi], start, end, tolerance);
214→      if (t === null) continue;
215→      splitPoints.push({ t, vi });
216→    }
217→
218→    splitPoints.sort((a, b) => a.t - b.t);
219→
220→    const orderedVertices = [];
221→    for (const split of splitPoints) {
222→      if (orderedVertices[orderedVertices.length - 1] !== split.vi) {
223→        orderedVertices.push(split.vi);
224→      }
225→    }
226→
227→    for (let i = 0; i < orderedVertices.length - 1; i++) {
228→      addUniqueEdge(edgeSet, edges, orderedVertices[i], orderedVertices[i + 1]);
229→    }
230→  }
231→
232→  return edges;
233→}
234→
235→function buildAdjacency(vertices, edges) {
236→  const adjacency = new Array(vertices.length).fill(null).map(() => []);
237→  const halfEdges = new Set();
238→
239→  for (const edge of edges) {
240→    const forward = `${edge.from}-${edge.to}`;
241→    const backward = `${edge.to}-${edge.from}`;
242→    if (!halfEdges.has(forward)) {
243→      halfEdges.add(forward);
244→      adjacency[edge.from].push(edge.to);
245→    }
246→    if (!halfEdges.has(backward)) {
247→      halfEdges.add(backward);
248→      adjacency[edge.to].push(edge.from);
249→    }
250→  }
251→
252→  for (let i = 0; i < vertices.length; i++) {
253→    const origin = vertices[i];
254→    adjacency[i].sort((a, b) => {
255→      const angleA = Math.atan2(vertices[a].y - origin.y, vertices[a].x - origin.x);
256→      const angleB = Math.atan2(vertices[b].y - origin.y, vertices[b].x - origin.x);
257→      return angleA - angleB;
258→    });
259→  }
260→
261→  return { adjacency, halfEdges };
262→}
263→
264→function traceFaces(vertices, edges) {
265→  const { adjacency, halfEdges } = buildAdjacency(vertices, edges);
266→  const nextHalfEdge = new Map();
267→
268→  for (const key of halfEdges) {
269→    const [uText, vText] = key.split('-');
270→    const u = Number.parseInt(uText, 10);
271→    const v = Number.parseInt(vText, 10);
272→    const neighbors = adjacency[v];
273→    const index = neighbors.indexOf(u);
274→    if (index === -1) continue;
275→    const nextIndex = (index - 1 + neighbors.length) % neighbors.length;
276→    nextHalfEdge.set(key, `${v}-${neighbors[nextIndex]}`);
277→  }
278→
279→  const visited = new Set();
280→  const cycles = [];
281→
282→  for (const startKey of halfEdges) {
283→    if (visited.has(startKey)) continue;
284→
285→    const cycle = [];
286→    let current = startKey;
287→    let steps = 0;
288→    const maxSteps = halfEdges.size + 1;
289→
290→    while (!visited.has(current) && steps < maxSteps) {
291→      visited.add(current);
292→      const [uText] = current.split('-');
293→      cycle.push(Number.parseInt(uText, 10));
294→      const next = nextHalfEdge.get(current);
295→      if (!next) break;
296→      current = next;
297→      steps++;
298→    }
299→
300→    if (current === startKey && cycle.length >= 3) {
301→      cycles.push(cycle);
302→    }
303→  }
304→
305→  return cycles;
306→}
307→
308→export function detectRoomFaces(walls, columns = [], mergeTolerance = ENDPOINT_MERGE_TOLERANCE) {
309→  if (walls.length < 3) return [];
310→
311→  const normalizedWalls = normalizeWallsForColumns(walls, columns, mergeTolerance);
312→  const vertices = [];
313→  const wallSegments = buildRawSegments(normalizedWalls, vertices, mergeTolerance);
314→  const columnSegments = buildColumnSegments(columns, vertices, mergeTolerance);
315→  const edges = subdivideSegments([...wallSegments, ...columnSegments], vertices, mergeTolerance);
316→  const cycles = traceFaces(vertices, edges);
317→  const faces = [];
318→  const seenKeys = new Set();
319→
320→  for (const cycle of cycles) {
321→    const points = cycle.map(index => vertices[index]);
322→    const signedArea = signedPolygonArea(points);
323→    const area = Math.abs(signedArea);
324→    if (signedArea <= 0 || area < MIN_ROOM_AREA) continue;
325→
326→    const key = roomPolygonKey(points, mergeTolerance);
327→    if (seenKeys.has(key)) continue;
328→    seenKeys.add(key);
329→
330→    faces.push({
331→      key,
332→      area,
333→      points: points.map(point => ({ x: point.x, y: point.y })),
334→    });
335→  }
336→
337→  return faces;
338→}
339→
340→export function detectRooms(walls, columns = [], mergeTolerance = ENDPOINT_MERGE_TOLERANCE) {
341→  return detectRoomFaces(walls, columns, mergeTolerance).map(face => ({
342→    points: face.points,
343→    area: face.area,
344→  }));
345→}
346→
347→export function findRoomFaceAtPoint(walls, columns = [], point, mergeTolerance = ENDPOINT_MERGE_TOLERANCE) {
348→  const faces = detectRoomFaces(walls, columns, mergeTolerance);
349→  const containingFaces = faces.filter(face => pointInPolygon(point, face.points));
350→  if (containingFaces.length === 0) return null;
351→
352→  containingFaces.sort((a, b) => a.area - b.area);
353→  return containingFaces[0];
354→}
355→
356→export { roomPolygonKey };
