 99→export function createDimensionFigure({
100→  id,
101→  startPoint,
102→  endPoint,
103→  mode = 'aligned',
104→  offset = 0,
105→  label,
106→  source = 'manual',
107→  sourceType = null,
108→  sourceId = null,
109→}) {
110→  let core = null;
111→
112→  if (mode === 'horizontal') core = buildHorizontalFigure(startPoint, endPoint, offset);
113→  else if (mode === 'vertical') core = buildVerticalFigure(startPoint, endPoint, offset);
114→  else core = buildAlignedFigure(startPoint, endPoint, offset);
115→
116→  if (!core || core.measurement < MIN_DIMENSION_LENGTH) return null;
117→
118→  const lineDirection = normalize(subtract(core.lineEnd, core.lineStart));
119→  const startArrow = createArrowHead(core.lineStart, lineDirection);
120→  const endArrow = createArrowHead(core.lineEnd, scale(lineDirection, -1));
121→
122→  return {
123→    id,
124→    type: 'dimension',
125→    source,
126→    sourceType,
127→    sourceId,
128→    mode,
129→    measurement: core.measurement,
130→    label: label || formatMeasurement(core.measurement),
131→    lineStart: core.lineStart,
132→    lineEnd: core.lineEnd,
133→    extensionLines: core.extensionLines,
134→    arrowheads: [startArrow, endArrow],
135→    text: {
136→      position: core.textPosition,
137→      angle: core.textAngle,
138→      value: label || formatMeasurement(core.measurement),
139→    },
140→    segments: [
141→      { start: core.lineStart, end: core.lineEnd },
142→      ...core.extensionLines,
143→      { start: startArrow.tip, end: startArrow.left },
144→      { start: startArrow.tip, end: startArrow.right },
145→      { start: endArrow.tip, end: endArrow.left },
146→      { start: endArrow.tip, end: endArrow.right },
147→    ],
148→  };
149→}
150→
151→function isInsideAnyFace(point, faces) {
152→  return faces.some((face) => pointInPolygon(point, face.points));
153→}
154→
155→function pickWallDimensionFigure(renderWall, faces, wallId) {
156→  const offset = renderWall.thickness / 2 + WALL_DIMENSION_GAP;
157→  const negative = createDimensionFigure({
158→    id: `wall-dim-${wallId}-neg`,
159→    startPoint: renderWall.start,
160→    endPoint: renderWall.end,
161→    mode: 'aligned',
162→    offset: -offset,
163→    source: 'derived',
164→    sourceType: 'wall',
165→    sourceId: wallId,
166→  });
167→  if (!negative) return null;
168→  if (!faces.length) return negative;
169→
170→  const positive = createDimensionFigure({
171→    id: `wall-dim-${wallId}-pos`,
172→    startPoint: renderWall.start,
173→    endPoint: renderWall.end,
174→    mode: 'aligned',
175→    offset,
176→    source: 'derived',
177→    sourceType: 'wall',
178→    sourceId: wallId,
179→  });
180→  if (!positive) return negative;
181→
182→  const negativeInside = isInsideAnyFace(negative.text.position, faces);
183→  const positiveInside = isInsideAnyFace(positive.text.position, faces);
184→
185→  if (negativeInside && !positiveInside) return positive;
186→  if (positiveInside && !negativeInside) return negative;
187→  return negative;
188→}
